def accuracy_reward(completions, solution, **kwargs):
    """Validates if model-generated answer is correct, supporting both symbolic verification and exact string matching."""
    import re
    import logging
    from datetime import datetime
    import math_verify
    import latex2sympy

    debug = kwargs.get('debug', False)
    if debug:
        logger = logging.getLogger('accuracy_reward')
        logger.setLevel(logging.INFO)
        handler = logging.FileHandler('accuracy_reward.log')
        handler.setFormatter(logging.Formatter('%(asctime)s - %(message)s'))
        logger.addHandler(handler)

    rewards = []
    for i, (comp, sol) in enumerate(zip(completions, solution)):
        # extract assistant content
        if isinstance(comp, list):
            # assume format [{"role": "assistant", "content": "..."}, ...]
            content = ''
            for msg in comp:
                if msg.get('role') == 'assistant':
                    content = msg.get('content', '')
                    break
        else:
            content = str(comp)
        # extract ground truth answer
        gt_answer = sol
        # try symbolic verification
        reward = 0.0
        try:
            # parse both sides
            expr_gen = latex2sympy.latex2sympy(content)
            expr_gt = latex2sympy.latex2sympy(gt_answer)
            if math_verify.verify(expr_gen, expr_gt):
                reward = 1.0
        except Exception:
            # symbolic verification failed, fallback to string matching
            # extract <answer> tags
            def extract_tag(s):
                m = re.search(r'<answer>(.*?)</answer>', s, re.DOTALL)
                if m:
                    return m.group(1).strip()
                return s.strip()
            gen_clean = extract_tag(content)
            gt_clean = extract_tag(gt_answer)
            if gen_clean == gt_clean:
                reward = 1.0
        rewards.append(reward)
        if debug:
            logger.info(f'idx {i}: reward {reward}, gen "{content}", gt "{gt_answer}"')
    return rewards
